import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Recipe {
  name: string;
  cookingTime: number;
  ingredientsCount: number;
  nutritionSummary: {
    calories: number;
    protein: number;
    carbs: number;
    fat: number;
  };
}

interface ResponseData {
  recipe: Recipe;
}

export default function Widget() {
  const { recipe } = response.data as ResponseData;
  const { name, cookingTime, ingredientsCount, nutritionSummary } = recipe;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: 'rgba(255, 255, 255, 0.8)', backdropFilter: 'blur(10px)' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
            {name}
          </Typography>
          <Stack direction="row" spacing={1} alignItems="center">
            <Chip label={`Time: ${cookingTime} min`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFC107', color: '#FFFFFF' }} />
            <Chip label={`Ingredients: ${ingredientsCount}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FFC107', color: '#FFFFFF' }} />
          </Stack>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Nutrition Summary:
            </Typography>
            <Stack direction="row" spacing={2} sx={{ mt: 0.5 }}>
              <Typography variant="caption" sx={{ color: '#FF5722' }}>Calories: {nutritionSummary.calories}</Typography>
              <Typography variant="caption" sx={{ color: '#FF5722' }}>Protein: {nutritionSummary.protein}g</Typography>
              <Typography variant="caption" sx={{ color: '#FF5722' }}>Carbs: {nutritionSummary.carbs}g</Typography>
              <Typography variant="caption" sx={{ color: '#FF5722' }}>Fat: {nutritionSummary.fat}g</Typography>
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
